func (c *Client) applyDoorDashBrowserHeaders(req *http.Request) {
	if c == nil || c.Config == nil || req == nil {
		return
	}
	// PATCH: DoorDash GraphQL endpoints expect browser-context headers even when driven by a CLI.
	if req.Header.Get("Accept") == "" {
		req.Header.Set("Accept", "application/json")
	}
	if req.Header.Get("Origin") == "" {
		req.Header.Set("Origin", strings.TrimRight(c.Config.BaseURL, "/"))
	}
	if req.Header.Get("Referer") == "" {
		req.Header.Set("Referer", strings.TrimRight(c.Config.BaseURL, "/")+"/")
	}
	if req.Header.Get("User-Agent") == "" && c.Config.UserAgent != "" {
		req.Header.Set("User-Agent", c.Config.UserAgent)
	}
	if req.Header.Get("X-CSRFToken") == "" {
		if token := c.csrfToken(); token != "" {
			req.Header.Set("X-CSRFToken", token)
		}
	}
	if req.Header.Get("X-Requested-With") == "" {
		req.Header.Set("X-Requested-With", "XMLHttpRequest")
	}
}

func (c *Client) csrfToken() string {
	if c == nil || c.Config == nil {
		return ""
	}
	if c.Config.CSRFToken != "" {
		return c.Config.CSRFToken
	}
	if c.cookieJar != nil {
		return c.cookieJar.CookieValue("csrf_token", "csrftoken", "csrf", "dd_csrf_token")
	}
	return ""
}

